var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아줌마! 호환이 되는 부품을 쓰라고 내가 몇 번을 말해?","JPN":"おばさん！　部品を使うときは互換性があるものにしてって何度言ったらわかるの？","ENG":"Hey! How many times do I have to tell you, use compatible parts!","TWN":"喂！用相容的零件，我說過多少次了？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"COLLECTOR_NPC_NULL_NULL","text":{"KOREA":"입 다물고 네 할일이나 해, 고양아. 이게 스펙이 제일 좋은 조합이라고.","JPN":"黙って仕事しろ、猫。これが最もハイスペックになる組み合わせなんだよ。","ENG":"Shut up and focus on your task, kitty. This is the combination with the best specs.","TWN":"閉嘴，做你該做的事，小貓咪。這是性能最好的組合。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L4_1","type":"dialog","speaker":"RAUL_SCAVENGER_NULL_NULL","text":{"KOREA":"아. 좋은 생각이 났어. 팔다리를 달아 준 다음 자기 마음에 들게 조립하라고 하자.","JPN":"あ、いいことを思いついたぜ。手足をつけてやって、こいつの好きなように組み立てさせるんだ。","ENG":"Ah. I have an idea. Let's give it arms and legs, and have it assemble itself.","TWN":"啊，我想到了一個好主意。我們給它裝上四肢，然後讓它自己裝吧？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"RAUL_SCAVENGER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"COLLECTOR_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"MAVERICK_NPC_NULL_NULL","text":{"KOREA":"또 코드를 수정하라고? 우릴 죽일 셈이야?","JPN":"またコードを修正しろって？　私たちを殺すつもりか？","ENG":"You want us to change the code again? Are you trying to kill us?","TWN":"又修改程式碼？你是想玩死我們嗎？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ALBERT_NPC_NULL_NULL","text":{"KOREA":"이제 남은 방법은 하나뿐이야. 하늘에 기도해서 우리를 대신해 줄 코드의 천사를 부르자.","JPN":"もう残された方法は1つだけ。神に祈って私たちの代わりになってくれるコードの天使を呼ぼう。","ENG":"There's only one option left. Let's pray for an angel of coding to come down and save us.","TWN":"現在就只剩下一個辦法了。對著上帝祈禱，召喚可以代替我們的程式碼天使過來。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"코드의 천사? 그런 편리한 방법이 있는데 왜 지금까지 쓰지 않았지?","JPN":"コードの天使？　そんな便利な方法があるなら、何で今まで使わなかったんだ？","ENG":"Angel of coding? Why didn't you call for them earlier?","TWN":"程式碼天使？既然有那麼簡單的辦法，為什麼到現在都不用？"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"……다들 제발 입 다물고 집중 좀 해!","JPN":"……頼むから黙って集中してくれ！","ENG":"...Everyone, be quiet and focus, please!","TWN":"……拜託大家都閉上嘴，專心幹活！"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"이봐, 제이나.","JPN":"おい、ジェイナ。","ENG":"Hey, Jaina.","TWN":"喂，婕娜。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"아, 네?! 앗!","JPN":"あ、はい！？　あっ！","ENG":"Oh, huh?! Ah!","TWN":"啊，是？！啊！"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"너무 놀라서 섭섭한데. 손에 든 것까지 떨어뜨리면 내가 괜히 머쓱해지잖아.","JPN":"そんなに驚かれるとは。手に持っていたものまで落とすほどだなんて、ちょっと申し訳ないな。","ENG":"I didn't think you'd be that surprised. Now it's awkward. You even dropped something.","TWN":"露出這麼驚訝的表情，我可是會很傷心的喔。而且害你手裡的東西掉了，我也會尷尬。"},"stage":{"bg":"CORRIDOR_04","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"음? 이건…… 주사위?","JPN":"うん？　これは……サイコロ？","ENG":"Hmm? This is... Dice?","TWN":"嗯？這是……骰子？"},"stage":{"bg":"MAINSTREAM_802","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"……네. 안토노프 중장님께서 주신 주사위에요.","JPN":"……はい、アントノフ中将から頂いたサイコロです。","ENG":"...Yes. Lieutenant General Antonov gave those dice to me.","TWN":"……是的，安東諾夫中將給的骰子。"},"stage":{"bg":"MAINSTREAM_802","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JAKE_DELTA_NEXT_NULL","text":{"KOREA":"사령관님께서?","JPN":"司令官が？","ENG":"The Commander?","TWN":"司令官？"},"stage":{"bg":"MAINSTREAM_802","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"네. 그 사람……. 그러니까, 도미닉의 소지품이라고 하셨어요.","JPN":"はい。あの人……ドミニークの所持品だそうです。","ENG":"Yes. She said it was that person's... I mean, Dominic's.","TWN":"是的，那個人……說是多明尼克的隨身物品。"},"stage":{"bg":"MAINSTREAM_802","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"참 이상하죠. 리플레이서 퀸과는 분명히 선을 그은 줄 알았는데.","JPN":"変ですよね。リプレイサー・クイーンとは完全に無関係になったと思っていたのですが。","ENG":"It's odd. I thought I drew the line between me and Replacer Queen.","TWN":"真奇怪。我以為已經和克隆·女皇劃清界限了呢。"},"stage":{"bg":"MAINSTREAM_802","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};